@Keep
class DeviceCompat(private val context: Context) {
    fun defaultObfuscatedId(prefix: String): String {
        val seed = buildSeed()
        val digest = sha256("$prefix:$seed")
        return digest.take(32)
    }

    private fun buildSeed(): String {
        val pkg = context.packageName ?: "pkg"
        val sdk = Build.VERSION.SDK_INT
        val model = Build.MODEL ?: "model"
        val brand = Build.BRAND ?: "brand"
        val installId = InstallId.getOrCreate(context)
        return "$pkg|$sdk|$brand|$model|$installId"
    }

    private fun sha256(s: String): String {
        val md = MessageDigest.getInstance("SHA-256")
        val bytes = md.digest(s.toByteArray(Charset.forName("UTF-8")))
        return bytes.joinToString("") { "%02x".format(it) }
    }
}

@Keep
object InstallId {
    private const val PREF = "pay_install_id_pref"
    private const val KEY = "install_id"

    fun getOrCreate(context: Context): String {
        val prefs = context.getSharedPreferences(PREF, Context.MODE_PRIVATE)
        val existing = prefs.getString(KEY, null)
        if (!existing.isNullOrBlank()) return existing
        val id = UUID.randomUUID().toString()
        prefs.edit().putString(KEY, id).apply()
        return id
    }
}

@Keep
class SecureStorage(context: Context) {
    private val prefs: SharedPreferences

    init {
        prefs = try {
            val masterKey = MasterKey.Builder(context)
                .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                .build()
            EncryptedSharedPreferences.create(
                context,
                "pay_secure_store",
                masterKey,
                EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
            )
        } catch (_: Throwable) {
            context.getSharedPreferences("pay_fallback_store", Context.MODE_PRIVATE)
        }
    }

    fun putString(key: String, value: String?) {
        if (value == null) prefs.edit().remove(key).apply()
        else prefs.edit().putString(key, value).apply()
    }

    fun getString(key: String, def: String? = null): String? = prefs.getString(key, def)

    fun putLong(key: String, value: Long) { prefs.edit().putLong(key, value).apply() }
    fun getLong(key: String, def: Long = 0L): Long = prefs.getLong(key, def)

    fun putBoolean(key: String, value: Boolean) { prefs.edit().putBoolean(key, value).apply() }
    fun getBoolean(key: String, def: Boolean = false): Boolean = prefs.getBoolean(key, def)

    fun remove(key: String) { prefs.edit().remove(key).apply() }
    fun clear() { prefs.edit().clear().apply() }
}

@Keep
class WalletStore(private val storage: SecureStorage) {
    private companion object {
        const val KEY_CURRENCY = "wallet_currency"
        const val KEY_BALANCE_MINOR = "wallet_balance_minor"
        const val KEY_UPDATED_AT = "wallet_updated_at"
        const val KEY_TX_LIST = "wallet_tx_list"
        const val KEY_AUTOCONSUME_PRODUCTS = "wallet_autoconsume_products"
        const val KEY_PURCHASE_TOKEN_CACHE = "purchase_token_cache"
        const val MAX_TX = 200
    }

    fun getBalance(): WalletBalance {
        val currency = storage.getString(KEY_CURRENCY, "USD") ?: "USD"
        val minor = storage.getLong(KEY_BALANCE_MINOR, 0L)
        val updatedAt = storage.getLong(KEY_UPDATED_AT, 0L)
        return WalletBalance(Money(currency, minor), updatedAt)
    }

    fun setCurrency(currency: String) {
        storage.putString(KEY_CURRENCY, currency)
    }

    fun configureAutoConsumeProducts(productIds: Set<String>) {
        val arr = JSONArray()
        productIds.forEach { arr.put(it) }
        storage.putString(KEY_AUTOCONSUME_PRODUCTS, arr.toString())
    }

    fun shouldAutoConsume(productId: String): Boolean {
        val raw = storage.getString(KEY_AUTOCONSUME_PRODUCTS, null) ?: return false
        return try {
            val arr = JSONArray(raw)
            (0 until arr.length()).any { arr.optString(it) == productId }
        } catch (_: Throwable) {
            false
        }
    }

    fun postTransaction(type: WalletTransaction.Type, amount: Money, metadata: Map<String, String>): WalletTransaction {
        val now = System.currentTimeMillis()
        val balance = getBalance()
        val currency = balance.available.currency
        require(amount.currency == currency) { "Currency mismatch: expected $currency, got ${amount.currency}" }
        require(amount.amountMinor > 0) { "Amount must be > 0" }

        val newMinor = when (type) {
            WalletTransaction.Type.CREDIT -> safeAdd(balance.available.amountMinor, amount.amountMinor)
            WalletTransaction.Type.DEBIT -> {
                val cur = balance.available.amountMinor
                require(cur >= amount.amountMinor) { "Insufficient balance" }
                cur - amount.amountMinor
            }
        }

        val tx = WalletTransaction(
            id = randomId("tx"),
            type = type,
            amount = amount,
            createdAtMs = now,
            status = WalletTransaction.Status.POSTED,
            metadata = metadata
        )

        val list = loadTxList().toMutableList()
        list.add(0, tx)
        while (list.size > MAX_TX) list.removeAt(list.lastIndex)
        saveTxList(list)

        storage.putLong(KEY_BALANCE_MINOR, newMinor)
        storage.putLong(KEY_UPDATED_AT, now)
        return tx
    }

    fun getTransactions(limit: Int = 50): List<WalletTransaction> {
        val list = loadTxList()
        return if (limit <= 0) emptyList() else list.take(limit)
    }

    fun recordPurchaseToken(purchaseToken: String, purchase: Purchase) {
        val cache = loadPurchaseTokenCache().toMutableMap()
        val obj = JSONObject()
        obj.put("token", purchaseToken)
        obj.put("orderId", purchase.orderId ?: "")
        obj.put("packageName", purchase.packageName ?: "")
        obj.put("purchaseTime", purchase.purchaseTime)
        obj.put("products", JSONArray(purchase.products))
        obj.put("signature", purchase.signature ?: "")
        obj.put("originalJson", purchase.originalJson ?: "")
        cache[purchaseToken] = obj.toString()
        savePurchaseTokenCache(cache)
    }

    fun getCachedPurchaseTokens(): Set<String> = loadPurchaseTokenCache().keys

    fun clearPurchaseTokenCache() {
        storage.remove(KEY_PURCHASE_TOKEN_CACHE)
    }

    private fun loadTxList(): List<WalletTransaction> {
        val raw = storage.getString(KEY_TX_LIST, null) ?: return emptyList()
        return try {
            val arr = JSONArray(raw)
            val out = ArrayList<WalletTransaction>(arr.length())
            for (i in 0 until arr.length()) {
                val o = arr.getJSONObject(i)
                val amount = Money(
                    currency = o.getString("currency"),
                    amountMinor = o.getLong("amountMinor")
                )
                val type = WalletTransaction.Type.valueOf(o.getString("type"))
                val status = WalletTransaction.Status.valueOf(o.getString("status"))
                val metaObj = o.optJSONObject("metadata")
                val meta = mutableMapOf<String, String>()
                if (metaObj != null) {
                    val it = metaObj.keys()
                    while (it.hasNext()) {
                        val k = it.next()
                        meta[k] = metaObj.optString(k)
                    }
                }
                out += WalletTransaction(
                    id = o.getString("id"),
                    type = type,
                    amount = amount,
                    createdAtMs = o.getLong("createdAtMs"),
                    status = status,
                    metadata = meta
                )
            }
            out
        } catch (_: Throwable) {
            emptyList()
        }
    }

    private fun saveTxList(list: List<WalletTransaction>) {
        val arr = JSONArray()
        list.forEach { tx ->
            val o = JSONObject()
            o.put("id", tx.id)
            o.put("type", tx.type.name)
            o.put("status", tx.status.name)
            o.put("createdAtMs", tx.createdAtMs)
            o.put("currency", tx.amount.currency)
            o.put("amountMinor", tx.amount.amountMinor)
            val meta = JSONObject()
            tx.metadata.forEach { (k, v) -> meta.put(k, v) }
            o.put("metadata", meta)
            arr.put(o)
        }
        storage.putString(KEY_TX_LIST, arr.toString())
    }

    private fun loadPurchaseTokenCache(): Map<String, String> {
        val raw = storage.getString(KEY_PURCHASE_TOKEN_CACHE, null) ?: return emptyMap()
        return try {
            val obj = JSONObject(raw)
            val out = HashMap<String, String>()
            val it = obj.keys()
            while (it.hasNext()) {
                val k = it.next()
                out[k] = obj.optString(k)
            }
            out
        } catch (_: Throwable) {
            emptyMap()
        }
    }

    private fun savePurchaseTokenCache(map: Map<String, String>) {
        val obj = JSONObject()
        map.forEach { (k, v) -> obj.put(k, v) }
        storage.putString(KEY_PURCHASE_TOKEN_CACHE, obj.toString())
    }

    private fun randomId(prefix: String): String {
        val bytes = ByteArray(16)
        SecureRandom().nextBytes(bytes)
        val b64 = Base64.encodeToString(bytes, Base64.NO_WRAP or Base64.URL_SAFE)
        return "${prefix}_$b64"
    }

    private fun safeAdd(a: Long, b: Long): Long {
        val r = a + b
        if (((a xor r) and (b xor r)) < 0) throw IllegalArgumentException("Balance overflow")
        return r
    }
}

